typedef struct {
    float weight;
    long assign;
    float cost;
} Point_Struct;

/* kernel 0 (placeholder to preserve kernel indexing expected by host code) */
__kernel void sc_placeholder_kernel(__global int *dummy) {
    size_t gid = get_global_id(0);
    if (dummy && gid == 0) {
        dummy[0] = dummy[0];
    }
}

/* kernel 1: pgain distance/cost contribution */
__kernel void sc_pgain_kernel(
    __global const Point_Struct *p,
    __global const float *coord,
    __global float *work_mem,
    __global const int *center_table,
    __global char *switch_membership,
    __local float *x_coord,
    const int num,
    const int dim,
    const long x,
    const int K
) {
    const int lid = get_local_id(0);
    const int lsize = get_local_size(0);
    const int gid = get_global_id(0);

    /* cache coordinates of candidate center x into local memory */
    for (int d = lid; d < dim; d += lsize) {
        x_coord[d] = coord[(long)d * (long)num + x];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if (gid >= num) return;

    float x_cost = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[(long)d * (long)num + (long)gid] - x_coord[d];
        x_cost += diff * diff;
    }
    x_cost *= p[gid].weight;

    const float current_cost = p[gid].cost;
    const long row = (long)gid * (long)(K + 1);

    if (x_cost < current_cost) {
        switch_membership[gid] = '1';
        work_mem[row + K] += (x_cost - current_cost);
    } else {
        long assign = p[gid].assign;
        int cidx = center_table[assign];
        work_mem[row + cidx] += (current_cost - x_cost);
    }
}
